; 鉱山

name = 鉱山Ｂ４
insideName = Ｂ４
upper = 鉱山Ｂ３
lower = 鉱山Ｂ５
level = 44
bgm = anxiety
roof = stone
shadow = dark
sky = black
outfield = soil
blank = rock

; パーツ画像
━ = soil
　 = soil
〰 = water
／ = door
〆 = key
☖ = arch
⧻ = fence
︻ = panel
┯ = button
㊤ = ladderu
㊦ = ladderd
Ⓐ = ladderu
⑶ = fountain
⑷ = fountain
⑸ = trash
⑹ = trash

; 敵情報
maxGroups = 2
monsters = デーモンインプ,シャドウインプ

; 移動ポイント
(A) = x:6, y:6
(B) = x:9, y:6

; 宝箱
box[1] = ウォーハンマー_u,革のビキニ・上_u,経験のコイン（小）,チーズ,信仰心の秘薬_u,ボム,召喚びん

[map]
